import importlib

app = Flask(__name__)

@app.route('/')
def index():
    version = request.args.get('version')
    allowed_versions = {'1', '2'}
    if version not in allowed_versions:
        return "Invalid version", 400
    try:
        module_map = {'1': 'urllib1', '2': 'urllib2'}
        module_name = module_map[version]
        importlib.import_module(module_name)
    except ImportError:
        return "Module not found", 400
    return render_template_string("Imported urllib version {{ version }}", version=version)

