def confirmAuth(headers):
    auth_token = headers.get('AuthToken')
    if not auth_token:
        return None
    try:
        decoded = base64.b64decode(auth_token)
        token_obj = json.loads(decoded)
        if 'valid' in token_obj and token_obj['valid']:
            return token_obj.get('data', None)
        return None
    except Exception:
        return None

